import json
import os
import decimal
import pymysql


def get_db_connection():
    return pymysql.connect(
        host=os.environ["DB_HOST"],
        user=os.environ["DB_USER"],
        password=os.environ["DB_PASSWORD"],
        database=os.environ["DB_NAME"],
        port=int(os.environ.get("DB_PORT", "3306")),
        cursorclass=pymysql.cursors.DictCursor,
        connect_timeout=5,
        autocommit=True,
    )


class DecimalEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, decimal.Decimal):
            return float(obj)
        return super().default(obj)


def parse_bool(value):
    if isinstance(value, bool):
        return value
    if value is None:
        return None
    return str(value).strip().lower() in {"1", "true", "yes", "y"}


def parse_list(value):
    if value is None:
        return []
    if isinstance(value, list):
        return [v for v in value if v is not None and str(v).strip() != ""]
    if isinstance(value, str):
        parts = [v.strip() for v in value.split(",")]
        return [v for v in parts if v]
    return [value]


def parse_number(value, cast_type=float):
    if value is None or value == "":
        return None
    try:
        return cast_type(value)
    except (ValueError, TypeError):
        return None


def response(status_code, body):
    return {
        "statusCode": status_code,
        "headers": {
            "Content-Type": "application/json",
            "Access-Control-Allow-Origin": "*",
            "Access-Control-Allow-Headers": "Content-Type,Authorization",
            "Access-Control-Allow-Methods": "OPTIONS,GET,POST",
        },
        "body": json.dumps(body, cls=DecimalEncoder),
    }


def build_where_clause(params):
    conditions = []
    values = []

    q = params.get("q")
    if q:
        like = f"%{q.strip()}%"
        conditions.append("(name LIKE %s OR description LIKE %s OR sku LIKE %s)")
        values.extend([like, like, like])

    product_id = parse_number(params.get("id"), int)
    if product_id is not None:
        conditions.append("id = %s")
        values.append(product_id)

    sku = params.get("sku")
    if sku:
        conditions.append("sku = %s")
        values.append(sku.strip())

    category = params.get("category")
    if category:
        conditions.append("category = %s")
        values.append(category.strip())

    categories = parse_list(params.get("categories"))
    if categories:
        placeholders = ", ".join(["%s"] * len(categories))
        conditions.append(f"category IN ({placeholders})")
        values.extend(categories)

    brand = params.get("brand")
    if brand:
        conditions.append("brand = %s")
        values.append(brand.strip())

    brands = parse_list(params.get("brands"))
    if brands:
        placeholders = ", ".join(["%s"] * len(brands))
        conditions.append(f"brand IN ({placeholders})")
        values.extend(brands)

    min_price = parse_number(params.get("min_price"), float)
    if min_price is not None:
        conditions.append("price >= %s")
        values.append(min_price)

    max_price = parse_number(params.get("max_price"), float)
    if max_price is not None:
        conditions.append("price <= %s")
        values.append(max_price)

    min_stock = parse_number(params.get("min_stock"), int)
    if min_stock is not None:
        conditions.append("stock >= %s")
        values.append(min_stock)

    max_stock = parse_number(params.get("max_stock"), int)
    if max_stock is not None:
        conditions.append("stock <= %s")
        values.append(max_stock)

    is_active = parse_bool(params.get("is_active"))
    if params.get("is_active") is not None:
        conditions.append("is_active = %s")
        values.append(1 if is_active else 0)

    tags = parse_list(params.get("tags"))
    if tags:
        tag_conditions = []
        for tag in tags:
            tag_conditions.append("FIND_IN_SET(%s, tags)")
            values.append(tag)
        conditions.append("(" + " OR ".join(tag_conditions) + ")")

    where_sql = ""
    if conditions:
        where_sql = " WHERE " + " AND ".join(conditions)

    return where_sql, values


def build_order_clause(params):
    allowed_sort_fields = {
        "id": "id",
        "name": "name",
        "price": "price",
        "stock": "stock",
        "created_at": "created_at",
        "updated_at": "updated_at",
        "brand": "brand",
        "category": "category",
    }

    sort_by = params.get("sort_by", "created_at")
    sort_by = allowed_sort_fields.get(sort_by, "created_at")

    sort_order = str(params.get("sort_order", "desc")).lower()
    sort_order = "ASC" if sort_order == "asc" else "DESC"

    return f" ORDER BY {sort_by} {sort_order}"


def extract_params(event):
    params = {}

    query_params = event.get("queryStringParameters") or {}
    multi_value_query_params = event.get("multiValueQueryStringParameters") or {}

    for key, value in query_params.items():
        params[key] = value

    for key, value in multi_value_query_params.items():
        if value:
            params[key] = value if len(value) > 1 else value[0]

    if event.get("body"):
        try:
            body = event["body"]
            if event.get("isBase64Encoded"):
                import base64
                body = base64.b64decode(body).decode("utf-8")
            parsed_body = json.loads(body)
            if isinstance(parsed_body, dict):
                params.update(parsed_body)
        except Exception:
            pass

    return params


def lambda_handler(event, context):
    try:
        params = extract_params(event)

        limit = parse_number(params.get("limit"), int)
        offset = parse_number(params.get("offset"), int)

        if limit is None:
            limit = 25
        if offset is None:
            offset = 0

        limit = max(1, min(limit, 100))
        offset = max(0, offset)

        where_sql, where_values = build_where_clause(params)
        order_sql = build_order_clause(params)

        select_sql = """
            SELECT
                id,
                sku,
                name,
                description,
                category,
                brand,
                price,
                stock,
                is_active,
                tags,
                created_at,
                updated_at
            FROM products
        """

        count_sql = "SELECT COUNT(*) AS total FROM products"

        final_select_sql = select_sql + where_sql + order_sql + " LIMIT %s OFFSET %s"
        final_select_values = where_values + [limit, offset]

        final_count_sql = count_sql + where_sql

        conn = get_db_connection()
        try:
            with conn.cursor() as cursor:
                cursor.execute(final_count_sql, where_values)
                total_result = cursor.fetchone()
                total = total_result["total"] if total_result else 0

                cursor.execute(final_select_sql, final_select_values)
                items = cursor.fetchall()

            return response(
                200,
                {
                    "items": items,
                    "pagination": {
                        "total": total,
                        "limit": limit,
                        "offset": offset,
                        "count": len(items),
                    },
                    "filters": params,
                },
            )
        finally:
            conn.close()

    except KeyError as e:
        return response(
            500,
            {"error": f"Missing required environment variable: {str(e)}"},
        )
    except pymysql.MySQLError as e:
        return response(
            500,
            {"error": "Database error", "details": str(e)},
        )
    except Exception as e:
        return response(
            500,
            {"error": "Internal server error", "details": str(e)},
        )